using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using PharmaAccess.Data.Entities;
using PharmaAccess.Domain.Entities;
using PharmaAccess.Domain.Features;

namespace PharmaAccess.Data.Configurations;

internal static class CausalMap { internal static void Text<TEntity>(EntityTypeBuilder<TEntity>b,string name,int length,bool required=true)where TEntity:class{var p=b.Property(name).HasMaxLength(length);if(required)p.IsRequired();} internal static void Number<TEntity>(EntityTypeBuilder<TEntity>b,params string[] names)where TEntity:class{foreach(var n in names)b.Property(n).HasPrecision(20,10);} internal static void Study<TEntity>(EntityTypeBuilder<TEntity>b,System.Linq.Expressions.Expression<Func<TEntity,object?>>fk)where TEntity:class=>b.HasOne<CausalStudyEntity>().WithMany().HasForeignKey(fk).OnDelete(DeleteBehavior.Restrict); }
public sealed class CausalDagDefinitionConfiguration:IEntityTypeConfiguration<CausalDagDefinitionEntity>{public void Configure(EntityTypeBuilder<CausalDagDefinitionEntity>b){b.ToTable("CausalDagDefinition","causal");b.HasKey(x=>x.CausalDagDefinitionId);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.VersionCode),64);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.Name),256);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.Description),2000,false);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.DefinitionJson),-1);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.DefinitionHash),64);CausalMap.Text(b,nameof(CausalDagDefinitionEntity.Notes),4000,false);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);b.HasIndex(x=>x.VersionCode).IsUnique();b.HasIndex(x=>x.DefinitionHash).IsUnique();}}
public sealed class CausalAdjustmentSetConfiguration:IEntityTypeConfiguration<CausalAdjustmentSetEntity>{public void Configure(EntityTypeBuilder<CausalAdjustmentSetEntity>b){b.ToTable("CausalAdjustmentSet","causal");b.HasKey(x=>x.CausalAdjustmentSetId);CausalMap.Text(b,nameof(CausalAdjustmentSetEntity.VersionCode),64);CausalMap.Text(b,nameof(CausalAdjustmentSetEntity.Name),256);CausalMap.Text(b,nameof(CausalAdjustmentSetEntity.VariablesJson),-1);CausalMap.Text(b,nameof(CausalAdjustmentSetEntity.DefinitionHash),64);CausalMap.Text(b,nameof(CausalAdjustmentSetEntity.Notes),4000,false);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);b.HasIndex(x=>x.VersionCode).IsUnique();b.HasIndex(x=>x.DefinitionHash).IsUnique();}}
public sealed class TreatmentDefinitionConfiguration:IEntityTypeConfiguration<TreatmentDefinitionEntity>{public void Configure(EntityTypeBuilder<TreatmentDefinitionEntity>b){b.ToTable("TreatmentDefinition","causal");b.HasKey(x=>x.TreatmentDefinitionId);CausalMap.Text(b,nameof(TreatmentDefinitionEntity.VersionCode),64);CausalMap.Text(b,nameof(TreatmentDefinitionEntity.TreatmentName),128);CausalMap.Text(b,nameof(TreatmentDefinitionEntity.ReferenceVersion),128);CausalMap.Text(b,nameof(TreatmentDefinitionEntity.DefinitionJson),-1);CausalMap.Text(b,nameof(TreatmentDefinitionEntity.DefinitionHash),64);b.Property(x=>x.ExposureType).HasConversion<string>().HasMaxLength(64);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);CausalMap.Number(b,nameof(TreatmentDefinitionEntity.Threshold));b.HasIndex(x=>x.VersionCode).IsUnique();b.HasIndex(x=>x.DefinitionHash).IsUnique();}}
public sealed class CausalStudyEntityConfiguration:IEntityTypeConfiguration<CausalStudyEntity>{public void Configure(EntityTypeBuilder<CausalStudyEntity>b){b.ToTable("CausalStudy","causal");b.HasKey(x=>x.CausalStudyId);foreach(var p in new[]{nameof(CausalStudyEntity.StudyCode),nameof(CausalStudyEntity.OutcomeDefinitionVersion),nameof(CausalStudyEntity.CodeCommitHash)})CausalMap.Text(b,p,64,p!=nameof(CausalStudyEntity.CodeCommitHash));CausalMap.Text(b,nameof(CausalStudyEntity.StudyName),256);CausalMap.Text(b,nameof(CausalStudyEntity.ResearchQuestion),2000);CausalMap.Text(b,nameof(CausalStudyEntity.TargetPopulation),1000);CausalMap.Text(b,nameof(CausalStudyEntity.Notes),4000,false);b.Property(x=>x.Estimand).HasConversion<string>().HasMaxLength(64);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);b.Property(x=>x.AssumptionStatus).HasConversion<string>().HasMaxLength(32);b.HasOne<DatasetVersion>().WithMany().HasForeignKey(x=>x.DatasetVersionId).OnDelete(DeleteBehavior.Restrict);b.HasOne<FeatureSetVersion>().WithMany().HasForeignKey(x=>x.FeatureSetVersionId).OnDelete(DeleteBehavior.Restrict);b.HasOne<CausalDagDefinitionEntity>().WithMany().HasForeignKey(x=>x.CausalDagDefinitionId).OnDelete(DeleteBehavior.Restrict);b.HasOne<CausalAdjustmentSetEntity>().WithMany().HasForeignKey(x=>x.CausalAdjustmentSetId).OnDelete(DeleteBehavior.Restrict);b.HasOne<TreatmentDefinitionEntity>().WithMany().HasForeignKey(x=>x.TreatmentDefinitionId).OnDelete(DeleteBehavior.Restrict);b.HasOne<QuarterDimension>().WithMany().HasForeignKey(x=>x.ObservationStartQuarterId).OnDelete(DeleteBehavior.Restrict);b.HasOne<QuarterDimension>().WithMany().HasForeignKey(x=>x.ObservationEndQuarterId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>x.StudyCode).IsUnique();}}
public sealed class CausalAnalysisRowConfiguration:IEntityTypeConfiguration<CausalAnalysisRowEntity>{public void Configure(EntityTypeBuilder<CausalAnalysisRowEntity>b){b.ToTable("CausalAnalysisRow","causal");b.HasKey(x=>x.CausalAnalysisRowId);CausalMap.Study(b,x=>x.CausalStudyId);b.HasOne<Drug>().WithMany().HasForeignKey(x=>x.DrugId).OnDelete(DeleteBehavior.Restrict);b.HasOne<State>().WithMany().HasForeignKey(x=>x.StateId).OnDelete(DeleteBehavior.Restrict);b.HasOne<QuarterDimension>().WithMany().HasForeignKey(x=>x.ObservationQuarterId).OnDelete(DeleteBehavior.Restrict);b.HasOne<QuarterDimension>().WithMany().HasForeignKey(x=>x.OutcomeQuarterId).OnDelete(DeleteBehavior.Restrict);CausalMap.Text(b,nameof(CausalAnalysisRowEntity.EligibilityStatus),32);CausalMap.Text(b,nameof(CausalAnalysisRowEntity.ExclusionReason),1000,false);CausalMap.Text(b,nameof(CausalAnalysisRowEntity.RowHash),64);CausalMap.Number(b,nameof(CausalAnalysisRowEntity.TreatmentValue),nameof(CausalAnalysisRowEntity.PropensityScore),nameof(CausalAnalysisRowEntity.OutcomeRegressionTreated),nameof(CausalAnalysisRowEntity.OutcomeRegressionUntreated),nameof(CausalAnalysisRowEntity.InfluenceFunctionValue),nameof(CausalAnalysisRowEntity.Weight));b.HasIndex(x=>new{x.CausalStudyId,x.DrugId,x.StateId,x.ObservationQuarterId}).IsUnique();b.HasIndex(x=>new{x.CausalStudyId,x.BinaryTreatment});}}
public sealed class CausalEstimateConfiguration:IEntityTypeConfiguration<CausalEstimateEntity>{public void Configure(EntityTypeBuilder<CausalEstimateEntity>b){b.ToTable("CausalEstimate","causal");b.HasKey(x=>x.CausalEstimateId);CausalMap.Study(b,x=>x.CausalStudyId);CausalMap.Text(b,nameof(CausalEstimateEntity.EstimatorName),128);CausalMap.Text(b,nameof(CausalEstimateEntity.Interpretation),2000);CausalMap.Text(b,nameof(CausalEstimateEntity.Limitations),4000);b.Property(x=>x.Estimand).HasConversion<string>().HasMaxLength(64);b.Property(x=>x.EffectScale).HasConversion<string>().HasMaxLength(32);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);CausalMap.Number(b,nameof(CausalEstimateEntity.Estimate),nameof(CausalEstimateEntity.StandardError),nameof(CausalEstimateEntity.ConfidenceIntervalLower),nameof(CausalEstimateEntity.ConfidenceIntervalUpper),nameof(CausalEstimateEntity.PValue),nameof(CausalEstimateEntity.EffectiveSampleSize));b.HasIndex(x=>new{x.CausalStudyId,x.EstimatorName,x.Estimand,x.EffectScale}).IsUnique();}}
public sealed class CausalDiagnosticConfiguration:IEntityTypeConfiguration<CausalDiagnosticEntity>{public void Configure(EntityTypeBuilder<CausalDiagnosticEntity>b){b.ToTable("CausalDiagnostic","causal");b.HasKey(x=>x.CausalDiagnosticId);CausalMap.Study(b,x=>x.CausalStudyId);CausalMap.Text(b,nameof(CausalDiagnosticEntity.DiagnosticType),64);CausalMap.Text(b,nameof(CausalDiagnosticEntity.VariableName),128,false);CausalMap.Text(b,nameof(CausalDiagnosticEntity.MetricName),128);CausalMap.Text(b,nameof(CausalDiagnosticEntity.Description),2000);CausalMap.Text(b,nameof(CausalDiagnosticEntity.Recommendation),2000);CausalMap.Number(b,nameof(CausalDiagnosticEntity.MetricValue),nameof(CausalDiagnosticEntity.Threshold));b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);b.Property(x=>x.Severity).HasConversion<string>().HasMaxLength(32);b.HasIndex(x=>new{x.CausalStudyId,x.DiagnosticType,x.VariableName,x.MetricName});}}
public sealed class CounterfactualScenarioConfiguration:IEntityTypeConfiguration<CounterfactualScenarioEntity>{public void Configure(EntityTypeBuilder<CounterfactualScenarioEntity>b){b.ToTable("CounterfactualScenario","causal");b.HasKey(x=>x.CounterfactualScenarioId);CausalMap.Study(b,x=>x.CausalStudyId);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.ScenarioCode),64);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.ScenarioName),256);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.Description),2000);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.InterventionDefinitionJson),-1);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.BaselinePolicy),512);CausalMap.Text(b,nameof(CounterfactualScenarioEntity.Notes),4000,false);b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(32);b.HasIndex(x=>new{x.CausalStudyId,x.ScenarioCode}).IsUnique();}}
public sealed class CounterfactualResultConfiguration:IEntityTypeConfiguration<CounterfactualResultEntity>{public void Configure(EntityTypeBuilder<CounterfactualResultEntity>b){b.ToTable("CounterfactualResult","causal");b.HasKey(x=>x.CounterfactualResultId);b.HasOne<CounterfactualScenarioEntity>().WithMany().HasForeignKey(x=>x.CounterfactualScenarioId).OnDelete(DeleteBehavior.Restrict);b.HasOne<Drug>().WithMany().HasForeignKey(x=>x.DrugId).OnDelete(DeleteBehavior.Restrict);b.HasOne<State>().WithMany().HasForeignKey(x=>x.StateId).OnDelete(DeleteBehavior.Restrict);b.HasOne<QuarterDimension>().WithMany().HasForeignKey(x=>x.ObservationQuarterId).OnDelete(DeleteBehavior.Restrict);CausalMap.Number(b,nameof(CounterfactualResultEntity.BaselinePredictedOutcome),nameof(CounterfactualResultEntity.InterventionPredictedOutcome),nameof(CounterfactualResultEntity.EstimatedDifference),nameof(CounterfactualResultEntity.UncertaintyLower),nameof(CounterfactualResultEntity.UncertaintyUpper));b.Property(x=>x.SupportStatus).HasConversion<string>().HasMaxLength(32);CausalMap.Text(b,nameof(CounterfactualResultEntity.WarningMessagesJson),8000);b.HasIndex(x=>new{x.CounterfactualScenarioId,x.DrugId,x.StateId,x.ObservationQuarterId});}}
